// Receive raw transcript response
const data = items[0].json;
return [{
  json: {
    meetingTitle: $json.meetingTitle,
    participants: $json.participants,
    transcriptText: data.transcript || data.text || '',
    clickupListId: $json.clickupListId,
    teamsChannelId: $json.teamsChannelId
  }
}];

const resp = items[0].json;
const content = resp.choices?.[0]?.message?.content || '';
let summary = '';
let actionItems = '';
try {
  const parsed = JSON.parse(content);
  summary = parsed.summary || parsed.notes || '';
  actionItems = parsed.action_items || parsed.actions || '';
} catch (e) {
  summary = content;
}
return [{ json: { summary, actionItems, meetingTitle: $json.meetingTitle, participants: $json.participants, clickupListId: $json.clickupListId, teamsChannelId: $json.teamsChannelId } }];

// Ensure actionItems is array of strings
let actions = $json.actionItems;
if (typeof actions === 'string') {
  actions = actions.split(/\n|•|-|\*/).map(a => a.trim()).filter(Boolean);
}
return [{ json: { summary: $json.summary, actionItems: actions, meetingTitle: $json.meetingTitle, participants: $json.participants, clickupListId: $json.clickupListId, teamsChannelId: $json.teamsChannelId } }];
